1947 /// Fold icmp eq/ne (or (xor/sub (X1, X2), xor/sub (X3, X4))), 0.
1948 static Value *foldICmpOrXorSubChain(ICmpInst &Cmp, BinaryOperator *Or,
1949                                     InstCombiner::BuilderTy &Builder) {
1950   // Are we using xors or subs to bitwise check for a pair or pairs of
1951   // (in)equalities? Convert to a shorter form that has more potential to be
1952   // folded even further.
1953   // ((X1 ^/- X2) || (X3 ^/- X4)) == 0 --> (X1 == X2) && (X3 == X4)
1954   // ((X1 ^/- X2) || (X3 ^/- X4)) != 0 --> (X1 != X2) || (X3 != X4)
1955   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) == 0 -->
1956   // (X1 == X2) && (X3 == X4) && (X5 == X6)
1957   // ((X1 ^/- X2) || (X3 ^/- X4) || (X5 ^/- X6)) != 0 -->
1958   // (X1 != X2) || (X3 != X4) || (X5 != X6)
1959   SmallVector<std::pair<Value *, Value *>, 2> CmpValues;
1960   SmallVector<Value *, 16> WorkList(1, Or);
1961 
1962   while (!WorkList.empty()) {
1963     auto MatchOrOperatorArgument = [&](Value *OrOperatorArgument) {
1964       Value *Lhs, *Rhs;
1965 
1966       if (match(OrOperatorArgument,
1967                 m_OneUse(m_Xor(m_Value(Lhs), m_Value(Rhs))))) {
1968         CmpValues.emplace_back(Lhs, Rhs);
1969         return;
1970       }
1971 
1972       if (match(OrOperatorArgument,
1973                 m_OneUse(m_Sub(m_Value(Lhs), m_Value(Rhs))))) {
1974         CmpValues.emplace_back(Lhs, Rhs);
1975         return;
1976       }
1977 
1978       WorkList.push_back(OrOperatorArgument);
1979     };
1980 
1981     Value *CurrentValue = WorkList.pop_back_val();
1982     Value *OrOperatorLhs, *OrOperatorRhs;
1983 
1984     if (!match(CurrentValue,
1985                m_Or(m_Value(OrOperatorLhs), m_Value(OrOperatorRhs)))) {
1986       return nullptr;
1987     }
1988 
1989     MatchOrOperatorArgument(OrOperatorRhs);
1990     MatchOrOperatorArgument(OrOperatorLhs);
1991   }
1992 
1993   ICmpInst::Predicate Pred = Cmp.getPredicate();
1994   auto BOpc = Pred == CmpInst::ICMP_EQ ? Instruction::And : Instruction::Or;
1995   Value *LhsCmp = Builder.CreateICmp(Pred, CmpValues.rbegin()->first,
1996                                      CmpValues.rbegin()->second);
1997 
1998   for (auto It = CmpValues.rbegin() + 1; It != CmpValues.rend(); ++It) {
1999     Value *RhsCmp = Builder.CreateICmp(Pred, It->first, It->second);
2000     LhsCmp = Builder.CreateBinOp(BOpc, LhsCmp, RhsCmp);
2001   }
2002 
2003   return LhsCmp;
2004 }
