2456       // icmp slt/ult (ashr X, ShAmtC), C --> icmp slt/ult X, (C << ShAmtC)
2457       APInt ShiftedC = C.shl(ShAmtVal);
2458       if (ShiftedC.ashr(ShAmtVal) == C)
2459         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2460     }
2461     if (Pred == CmpInst::ICMP_SGT) {
2462       // icmp sgt (ashr X, ShAmtC), C --> icmp sgt X, ((C + 1) << ShAmtC) - 1
2463       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2464       if (!C.isMaxSignedValue() && !(C + 1).shl(ShAmtVal).isMinSignedValue() &&
2465           (ShiftedC + 1).ashr(ShAmtVal) == (C + 1))
2466         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2467     }
2468     if (Pred == CmpInst::ICMP_UGT) {
2469       // icmp ugt (ashr X, ShAmtC), C --> icmp ugt X, ((C + 1) << ShAmtC) - 1
2470       // 'C + 1 << ShAmtC' can overflow as a signed number, so the 2nd
2471       // clause accounts for that pattern.
2472       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2473       if ((ShiftedC + 1).ashr(ShAmtVal) == (C + 1) ||
2474           (C + 1).shl(ShAmtVal).isMinSignedValue())
2475         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2476     }
2477 
2478     // If the compare constant has significant bits above the lowest sign-bit,
2479     // then convert an unsigned cmp to a test of the sign-bit:
2480     // (ashr X, ShiftC) u> C --> X s< 0
2481     // (ashr X, ShiftC) u< C --> X s> -1
2482     if (C.getBitWidth() > 2 && C.getNumSignBits() <= ShAmtVal) {
2483       if (Pred == CmpInst::ICMP_UGT) {
2484         return new ICmpInst(CmpInst::ICMP_SLT, X,
2485                             ConstantInt::getNullValue(ShrTy));
2486       }
2487       if (Pred == CmpInst::ICMP_ULT) {
2488         return new ICmpInst(CmpInst::ICMP_SGT, X,
2489                             ConstantInt::getAllOnesValue(ShrTy));
2490       }
2491     }
2492   } else {
2493     if (Pred == CmpInst::ICMP_ULT || (Pred == CmpInst::ICMP_UGT && IsExact)) {
2494       // icmp ult (lshr X, ShAmtC), C --> icmp ult X, (C << ShAmtC)
2495       // icmp ugt (lshr exact X, ShAmtC), C --> icmp ugt X, (C << ShAmtC)
2496       APInt ShiftedC = C.shl(ShAmtVal);
2497       if (ShiftedC.lshr(ShAmtVal) == C)
2498         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2499     }
2500     if (Pred == CmpInst::ICMP_UGT) {
2501       // icmp ugt (lshr X, ShAmtC), C --> icmp ugt X, ((C + 1) << ShAmtC) - 1
2502       APInt ShiftedC = (C + 1).shl(ShAmtVal) - 1;
2503       if ((ShiftedC + 1).lshr(ShAmtVal) == (C + 1))
2504         return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, ShiftedC));
2505     }
2506   }
2507 
2508   if (!Cmp.isEquality())
2509     return nullptr;
2510 
2511   // Handle equality comparisons of shift-by-constant.
2512 
2513   // If the comparison constant changes with the shift, the comparison cannot
2514   // succeed (bits of the comparison constant cannot match the shifted value).
2515   // This should be known by InstSimplify and already be folded to true/false.
2516   assert(((IsAShr && C.shl(ShAmtVal).ashr(ShAmtVal) == C) ||
2517           (!IsAShr && C.shl(ShAmtVal).lshr(ShAmtVal) == C)) &&
2518          "Expected icmp+shr simplify did not occur.");
2519 
2520   // If the bits shifted out are known zero, compare the unshifted value:
2521   //  (X & 4) >> 1 == 2  --> (X & 4) == 4.
2522   if (Shr->isExact())
2523     return new ICmpInst(Pred, X, ConstantInt::get(ShrTy, C << ShAmtVal));
2524 
2525   if (C.isZero()) {
2526     // == 0 is u< 1.
2527     if (Pred == CmpInst::ICMP_EQ)
2528       return new ICmpInst(CmpInst::ICMP_ULT, X,
2529                           ConstantInt::get(ShrTy, (C + 1).shl(ShAmtVal)));
2530     else
2531       return new ICmpInst(CmpInst::ICMP_UGT, X,
2532                           ConstantInt::get(ShrTy, (C + 1).shl(ShAmtVal) - 1));
2533   }
2534 
2535   if (Shr->hasOneUse()) {
2536     // Canonicalize the shift into an 'and':
2537     // icmp eq/ne (shr X, ShAmt), C --> icmp eq/ne (and X, HiMask), (C << ShAmt)
2538     APInt Val(APInt::getHighBitsSet(TypeBits, TypeBits - ShAmtVal));
2539     Constant *Mask = ConstantInt::get(ShrTy, Val);
2540     Value *And = Builder.CreateAnd(X, Mask, Shr->getName() + ".mask");
2541     return new ICmpInst(Pred, And, ConstantInt::get(ShrTy, C << ShAmtVal));
2542   }
2543 
2544   return nullptr;
2545 }
