2547 Instruction *InstCombinerImpl::foldICmpSRemConstant(ICmpInst &Cmp,
2548                                                     BinaryOperator *SRem,
2549                                                     const APInt &C) {
2550   // Match an 'is positive' or 'is negative' comparison of remainder by a
2551   // constant power-of-2 value:
2552   // (X % pow2C) sgt/slt 0
2553   const ICmpInst::Predicate Pred = Cmp.getPredicate();
2554   if (Pred != ICmpInst::ICMP_SGT && Pred != ICmpInst::ICMP_SLT &&
2555       Pred != ICmpInst::ICMP_EQ && Pred != ICmpInst::ICMP_NE)
2556     return nullptr;
2557 
2558   // TODO: The one-use check is standard because we do not typically want to
2559   //       create longer instruction sequences, but this might be a special-case
2560   //       because srem is not good for analysis or codegen.
2561   if (!SRem->hasOneUse())
2562     return nullptr;
2563 
2564   const APInt *DivisorC;
2565   if (!match(SRem->getOperand(1), m_Power2(DivisorC)))
2566     return nullptr;
2567 
2568   // For cmp_sgt/cmp_slt only zero valued C is handled.
2569   // For cmp_eq/cmp_ne only positive valued C is handled.
2570   if (((Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SLT) &&
2571        !C.isZero()) ||
2572       ((Pred == ICmpInst::ICMP_EQ || Pred == ICmpInst::ICMP_NE) &&
2573        !C.isStrictlyPositive()))
2574     return nullptr;
2575 
2576   // Mask off the sign bit and the modulo bits (low-bits).
2577   Type *Ty = SRem->getType();
2578   APInt SignMask = APInt::getSignMask(Ty->getScalarSizeInBits());
2579   Constant *MaskC = ConstantInt::get(Ty, SignMask | (*DivisorC - 1));
